package com.eafc26.discordstats.discord
import com.eafc26.discordstats.config.PhraseBank import com.eafc26.discordstats.config.PhraseCategory import com.eafc26.discordstats.ea.model.PlayerEntry import java.util.Random import kotlin.math.abs
/** * Evaluates a goalkeeper's match and produces a [GoalkeeperPerformance]. * * ## Classification logic * * The **EA rating** is the primary verdict. The save-type statistics enrich * the classification when the raw counts tell a story the rating alone cannot: * a goalkeeper who faced 10 shots and conceded 2 goals is *Bombardeado*, not * *Mão de Alface*, even if the rating is below 6.0. * * Priority order (first matching rule wins): * * | Priority | Archetype | Condition | * |----------|----------------|----------------------------------------------------------------------| * | 1 | QUIET | saves ≤ 1 **and** goalsConceded ≤ 1 — barely worked | * | 2 | WALL | rating ≥ 7.5 **and** (cleanSheet **or** impactSaves ≥ 3) | * | 3 | UNDER_SIEGE | saves ≥ [MIN_SAVES_UNDER_SIEGE] — bombarded regardless of rating | * | 4 | POOR | rating < [POOR_RATING_THRESHOLD] — low rating, few saves | * | 5 | SOLID | everything else | * * **impactSaves** = goodDirectionSaves + reflexSaves + parrySaves * * These are the three EA save types that indicate a demanding intervention. * punchSaves, ballDiveSaves and crossSaves are not counted as "impact" because * they represent routine distribution or positional play. */ object GoalkeeperEvaluator {
/** Total saves threshold to classify a goalkeeper as UNDER_SIEGE. */ const val MIN_SAVES_UNDER_SIEGE = 6
/** Rating below which a goalkeeper is classified as POOR (when not UNDER_SIEGE). */ const val POOR_RATING_THRESHOLD = 6.0
/** Rating at or above which WALL is considered (combined with other criteria). */ const val WALL_RATING_THRESHOLD = 7.5
/** Minimum impact saves to qualify for WALL even when goals were conceded. */ const val WALL_MIN_IMPACT_SAVES = 3
data class GoalkeeperPerformance( val archetype: GoalkeeperArchetype, /** Localised title, e.g. " Paredão". */ val title: String, /** Selected contextual phrase for Discord / web card. */ val message: String, )
/** * Evaluates [gk] and returns the appropriate [GoalkeeperPerformance]. * * @param gk Goalkeeper [PlayerEntry]. * @param matchId Used for deterministic phrase selection. * @param phraseBank Optional custom phrases; falls back to category defaults. * @param random When non-null, uses random selection (dev simulator). */ fun evaluate( gk: PlayerEntry, matchId: String, phraseBank: PhraseBank?, random: Random? = null, ): GoalkeeperPerformance { val saves = gk.saves?.toIntOrNull() ?: 0 val goalsConceded = gk.goalsConceded?.toIntOrNull() ?: 0 val rating = gk.rating?.toDoubleOrNull() ?: 0.0
val goodDirection = gk.goodDirectionSaves?.toIntOrNull() ?: 0 val reflex = gk.reflexSaves?.toIntOrNull() ?: 0 val parry = gk.parrySaves?.toIntOrNull() ?: 0 val impactSaves = goodDirection + reflex + parry
val cleanSheet = goalsConceded == 0
val archetype = classify(saves, goalsConceded, rating, impactSaves, cleanSheet) val category = phraseCategory(archetype) val message = pick(category, matchId, gk.displayName(), phraseBank, random)
return GoalkeeperPerformance( archetype = archetype, title = archetype.title, message = message, ) }
// ── Classification ────────────────────────────────────────────────────────
internal fun classify( saves: Int, goalsConceded: Int, rating: Double, impactSaves: Int, cleanSheet: Boolean, ): GoalkeeperArchetype = when { // 1. Barely worked saves <= 1 && goalsConceded <= 1 -> GoalkeeperArchetype.QUIET
// 2. Outstanding: high rating with clean sheet or decisive saves rating >= WALL_RATING_THRESHOLD && (cleanSheet || impactSaves >= WALL_MIN_IMPACT_SAVES) -> GoalkeeperArchetype.WALL
// 3. Bombarded: many saves — defence exposed the goalkeeper saves >= MIN_SAVES_UNDER_SIEGE -> GoalkeeperArchetype.UNDER_SIEGE
// 4. Poor: low rating and not bombarded rating < POOR_RATING_THRESHOLD -> GoalkeeperArchetype.POOR
// 5. Default: decent performance else -> GoalkeeperArchetype.SOLID }
// ── Phrase category mapping ───────────────────────────────────────────────
internal fun phraseCategory(archetype: GoalkeeperArchetype): PhraseCategory = when (archetype) { GoalkeeperArchetype.WALL -> PhraseCategory.GOALKEEPER_WALL GoalkeeperArchetype.SOLID -> PhraseCategory.GOALKEEPER_SOLID GoalkeeperArchetype.UNDER_SIEGE -> PhraseCategory.GOALKEEPER_UNDER_SIEGE GoalkeeperArchetype.POOR -> PhraseCategory.GOALKEEPER_POOR GoalkeeperArchetype.QUIET -> PhraseCategory.GOALKEEPER_QUIET }
// ── Phrase selection ──────────────────────────────────────────────────────
private fun pick( cat: PhraseCategory, matchId: String, seed: String, phraseBank: PhraseBank?, random: Random?, ): String { val list = phraseBank?.get(cat) ?: cat.defaults return if (random != null) { list[random.nextInt(list.size)] } else { val hash = matchId.hashCode().toLong() + seed.hashCode().toLong() list[(abs(hash) % list.size).toInt()] } } }

package com.eafc26.discordstats.discord

import com.eafc26.discordstats.config.PhraseBank
import com.eafc26.discordstats.config.PhraseCategory
import com.eafc26.discordstats.ea.model.PlayerEntry
import java.util.Random
import kotlin.math.abs

/**
 * Evaluates a goalkeeper's match and produces a [GoalkeeperPerformance].
 *
 * ## Classification logic
 *
 * The **EA rating** is the primary verdict. Raw save counts enrich the
 * interpretation but never override a clearly poor rating.
 *
 * Priority order (first matching rule wins):
 *
 *  Priority  Archetype       Condition
 * ------------------------------------------------------------------------------------------
 *  1         QUIET           saves ≤ 1 **and** goalsConceded ≤ 1 — barely worked
 *  2         WALL            rating ≥ [WALL_RATING_THRESHOLD] **and** (cleanSheet **or** impactSaves ≥ [WALL_MIN_IMPACT_SAVES])
 *  3         POOR            rating < [POOR_RATING_THRESHOLD] — EA verdict takes priority over save count
 *  4         UNDER_SIEGE     saves ≥ [MIN_SAVES_UNDER_SIEGE] — bombarded with acceptable rating
 *  5         SOLID           everything else
 *
 * **impactSaves** = goodDirectionSaves + reflexSaves + parrySaves
 */
object GoalkeeperEvaluator {

    /** Total saves threshold to classify a goalkeeper as UNDER_SIEGE. */
    const val MIN_SAVES_UNDER_SIEGE = 6

    /** Rating below which a goalkeeper is classified as POOR (checked before UNDER_SIEGE). */
    const val POOR_RATING_THRESHOLD = 6.0

    /** Rating at or above which WALL is considered (combined with other criteria). */
    const val WALL_RATING_THRESHOLD = 8.0

    /** Minimum impact saves to qualify for WALL even when goals were conceded. */
    const val WALL_MIN_IMPACT_SAVES = 3

    /** Minimum notable count for a save type to be considered dominant. */
    private const val DOMINANT_SAVE_THRESHOLD = 3

    data class GoalkeeperPerformance(
        val archetype: GoalkeeperArchetype,
        /** Localised title, e.g. " Paredão". */
        val title: String,
        /** Selected contextual phrase for Discord / web card. */
        val message: String,
    )

    // ── Contextual phrase pools ───────────────────────────────────────────────

    private val CONTEXTUAL_REFLEX = listOf(
        "Fez defesas praticamente impossíveis.",
        "Os reflexos fizeram a diferença.",
        "Respondeu rápido em cada situação de perigo.",
        "O instinto salvou o time mais de uma vez.",
        "Tirou de onde não havia mais tempo para pensar.",
    )

    private val CONTEXTUAL_PARRY = listOf(
        "Espalmou tudo que apareceu.",
        "Tirou o perigo com firmeza em cada oportunidade.",
        "As espalmadas mantiveram o time vivo.",
        "Cada intervenção foi precisa e segura.",
        "A luva trabalhou em horas extras.",
    )

    private val CONTEXTUAL_CROSS = listOf(
        "Dominou completamente a área.",
        "Saiu com autoridade em cada bola aérea.",
        "O domínio da área foi total.",
        "Transmitiu segurança nas saídas.",
        "Limpou a área com eficiência.",
    )

    private val CONTEXTUAL_GOOD_DIRECTION = listOf(
        "Leu muito bem as finalizações.",
        "Antecipou os chutes com inteligência.",
        "Posicionamento impecável nas defesas.",
        "Sabia para onde a bola ia antes do chute.",
        "A leitura de jogo foi o grande diferencial.",
    )

    // Tiered POOR phrases — selected based on how poor the rating was
    private val POOR_MILD = listOf(
        "Não conseguiu passar segurança.",
        "A atuação deixou a desejar.",
        "Houve momentos de hesitação que custaram caro.",
        "Não foi o jogo que o time precisava do goleiro.",
        "A segurança que o setor precisava não apareceu.",
        "Oscilou mais do que o ideal nas intervenções.",
    )

    private val POOR_MODERATE = listOf(
        "As intervenções não evitaram os gols sofridos.",
        "Quando o time precisou, a resposta não veio.",
        "Os gols sofridos disseram mais que as defesas.",
        "A luva não ajudou hoje.",
        "Hoje o gol foi mais fácil de fazer.",
        "A defesa errou e o goleiro não compensou.",
    )

    private val POOR_SEVERE = listOf(
        "Hoje qualquer chute parecia perigoso.",
        "A goleira virou uma meta aberta.",
        "Cada finalização era uma ameaça real.",
        "O adversário entendeu cedo que marcar era questão de tempo.",
        "A falta de segurança contaminou todo o setor.",
        "O time defendeu praticamente sem goleiro.",
    )

    // ── Public API ────────────────────────────────────────────────────────────

    /**
     * Evaluates [gk] and returns the appropriate [GoalkeeperPerformance].
     */
    fun evaluate(
        gk: PlayerEntry,
        matchId: String,
        phraseBank: PhraseBank?,
        random: Random? = null,
    ): GoalkeeperPerformance {
        val saves         = gk.saves?.toIntOrNull()         ?: 0
        val goalsConceded = gk.goalsConceded?.toIntOrNull() ?: 0
        val rating        = gk.rating?.toDoubleOrNull()     ?: 0.0

        val goodDirection = gk.goodDirectionSaves?.toIntOrNull() ?: 0
        val reflex        = gk.reflexSaves?.toIntOrNull()        ?: 0
        val parry         = gk.parrySaves?.toIntOrNull()         ?: 0
        val cross         = gk.crossSaves?.toIntOrNull()         ?: 0
        val impactSaves   = goodDirection + reflex + parry

        val cleanSheet = goalsConceded == 0

        val archetype = classify(saves, goalsConceded, rating, impactSaves, cleanSheet)
        val category  = phraseCategory(archetype)
        val message   = selectMessage(
            archetype     = archetype,
            category      = category,
            rating        = rating,
            reflex        = reflex,
            parry         = parry,
            cross         = cross,
            goodDirection = goodDirection,
            matchId       = matchId,
            seed          = gk.displayName(),
            phraseBank    = phraseBank,
            random        = random,
        )

        return GoalkeeperPerformance(
            archetype = archetype,
            title     = archetype.title,
            message   = message,
        )
    }

    // ── Classification ────────────────────────────────────────────────────────

    internal fun classify(
        saves: Int,
        goalsConceded: Int,
        rating: Double,
        impactSaves: Int,
        cleanSheet: Boolean,
    ): GoalkeeperArchetype = when {
        // 1. Barely worked
        saves <= 1 && goalsConceded <= 1 ->
            GoalkeeperArchetype.QUIET

        // 2. Outstanding: high rating with clean sheet or decisive saves
        rating >= WALL_RATING_THRESHOLD && (cleanSheet || impactSaves >= WALL_MIN_IMPACT_SAVES) ->
            GoalkeeperArchetype.WALL

        // 3. Poor: EA rating is the primary verdict — wins over save count
        rating < POOR_RATING_THRESHOLD ->
            GoalkeeperArchetype.POOR

        // 4. Bombarded: many saves with acceptable rating (implicitly rating ≥ 6.0)
        saves >= MIN_SAVES_UNDER_SIEGE ->
            GoalkeeperArchetype.UNDER_SIEGE

        // 5. Default: decent performance
        else ->
            GoalkeeperArchetype.SOLID
    }

    // ── Phrase category mapping ───────────────────────────────────────────────

    internal fun phraseCategory(archetype: GoalkeeperArchetype): PhraseCategory = when (archetype) {
        GoalkeeperArchetype.WALL        -> PhraseCategory.GOALKEEPER_WALL
        GoalkeeperArchetype.SOLID       -> PhraseCategory.GOALKEEPER_SOLID
        GoalkeeperArchetype.UNDER_SIEGE -> PhraseCategory.GOALKEEPER_UNDER_SIEGE
        GoalkeeperArchetype.POOR        -> PhraseCategory.GOALKEEPER_POOR
        GoalkeeperArchetype.QUIET       -> PhraseCategory.GOALKEEPER_QUIET
    }

    // ── Phrase selection ──────────────────────────────────────────────────────

    private enum class DominantSave { REFLEX, PARRY, CROSS, GOOD_DIRECTION, NONE }

    private fun dominantSaveType(reflex: Int, parry: Int, cross: Int, goodDirection: Int): DominantSave {
        val best = maxOf(reflex, parry, goodDirection)
        return when {
            best < DOMINANT_SAVE_THRESHOLD && cross < DOMINANT_SAVE_THRESHOLD -> DominantSave.NONE
            reflex == best && reflex >= DOMINANT_SAVE_THRESHOLD -> DominantSave.REFLEX
            parry == best && parry >= DOMINANT_SAVE_THRESHOLD   -> DominantSave.PARRY
            goodDirection >= DOMINANT_SAVE_THRESHOLD             -> DominantSave.GOOD_DIRECTION
            cross >= DOMINANT_SAVE_THRESHOLD                     -> DominantSave.CROSS
            else                                                  -> DominantSave.NONE
        }
    }

    /**
     * Selects a contextual message:
     * - POOR: tiered by rating severity (ignores phraseBank for richer variety unless customised)
     * - WALL / UNDER_SIEGE with dominant save type: returns a stat-contextual phrase
     * - Everything else: falls back to phraseBank → category defaults
     */
    private fun selectMessage(
        archetype: GoalkeeperArchetype,
        category: PhraseCategory,
        rating: Double,
        reflex: Int,
        parry: Int,
        cross: Int,
        goodDirection: Int,
        matchId: String,
        seed: String,
        phraseBank: PhraseBank?,
        random: Random?,
    ): String {
        // POOR: if no custom phrases, use tiered defaults for better variety
        if (archetype == GoalkeeperArchetype.POOR) {
            val custom = phraseBank?.get(category)
            if (custom != null && custom.isNotEmpty() && custom != category.defaults) {
                return pickFrom(custom, matchId, seed, random)
            }
            val tiered = when {
                rating < 4.5 -> POOR_SEVERE
                rating < 5.5 -> POOR_MODERATE
                else         -> POOR_MILD
            }
            return pickFrom(tiered, matchId, seed, random)
        }

        // WALL / UNDER_SIEGE: enrich with dominant save type contextual phrases
        if (archetype == GoalkeeperArchetype.WALL || archetype == GoalkeeperArchetype.UNDER_SIEGE) {
            val dominant = dominantSaveType(reflex, parry, cross, goodDirection)
            val contextual: List<String>? = when (dominant) {
                DominantSave.REFLEX         -> CONTEXTUAL_REFLEX
                DominantSave.PARRY          -> CONTEXTUAL_PARRY
                DominantSave.CROSS          -> CONTEXTUAL_CROSS
                DominantSave.GOOD_DIRECTION -> CONTEXTUAL_GOOD_DIRECTION
                DominantSave.NONE           -> null
            }
            if (contextual != null) return pickFrom(contextual, matchId, seed, random)
        }

        return pick(category, matchId, seed, phraseBank, random)
    }

    private fun pick(
        cat: PhraseCategory,
        matchId: String,
        seed: String,
        phraseBank: PhraseBank?,
        random: Random?,
    ): String {
        val list = phraseBank?.get(cat) ?: cat.defaults
        return pickFrom(list, matchId, seed, random)
    }

    private fun pickFrom(list: List<String>, matchId: String, seed: String, random: Random?): String {
        return if (random != null) {
            list[random.nextInt(list.size)]
        } else {
            val hash = matchId.hashCode().toLong() + seed.hashCode().toLong()
            list[(abs(hash) % list.size).toInt()]
        }
    }
}

package com.eafc26.discordstats.discord

import com.eafc26.discordstats.ea.model.ClubDetails
import com.eafc26.discordstats.ea.model.ClubMatchEntry
import com.eafc26.discordstats.ea.model.MatchResponse
import com.eafc26.discordstats.ea.model.PlayerEntry
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test
import java.time.ZoneId

/**
 * Tests for goalkeeper display in Discord embed.
 *
 * Key requirements:
 * - BOT goalkeeper with saves should be displayed
 * - Human goalkeeper with saves should be displayed
 * - Blank BOT name falls back to "Goleiro BOT"
 * - Goalkeeper saves remain attached to the correct player
 * - BOT goalkeeper never appears in player awards (Craque, Bagre, etc.)
 * - The goalkeeper section shows the archetype title (e.g. " Paredão")
 */
class GoalkeeperDisplayTest {

    private val ourClubId = "1104972"
    private val oppClubId = "99999"
    private val zone = ZoneId.of("America/Sao_Paulo")

    @Test
    fun `BOT goalkeeper with saves is displayed`() {
        val match = createMatchWithGoalkeeper(
            gkName = null,
            gkPosition = "0",
            gkSaves = "5",
            gkGoalsConceded = "2",
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField).isNotNull
        assertThat(gkField!!.value).contains("Goleiro BOT")
        assertThat(gkField.value).contains("5 defesas")
        assertThat(gkField.value).contains("2 gols sofridos")
    }

    @Test
    fun `human goalkeeper with saves is displayed`() {
        val match = createMatchWithGoalkeeper(
            gkName = "João Goleiro",
            gkPosition = "0",
            gkSaves = "7",
            gkGoalsConceded = "1",
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField).isNotNull
        assertThat(gkField!!.value).contains("João Goleiro")
        assertThat(gkField.value).contains("7 defesas")
        assertThat(gkField.value).contains("1 gol sofrido")  // singular
    }

    @Test
    fun `blank BOT name falls back to Goleiro BOT`() {
        val match = createMatchWithGoalkeeper(
            gkName = "   ",
            gkPosition = "0",
            gkSaves = "3",
            gkGoalsConceded = "0",
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField).isNotNull
        assertThat(gkField!!.value).contains("Goleiro BOT")
    }

    @Test
    fun `goalkeeper with position code 0 is detected`() {
        val gk = PlayerEntry(playerName = "TestGK", position = "0", saves = "5")
        assertThat(gk.isGoalkeeper()).isTrue()
    }

    @Test
    fun `goalkeeper with string goalkeeper is detected for backwards compatibility`() {
        val gk = PlayerEntry(playerName = "TestGK", position = "goalkeeper", saves = "5")
        assertThat(gk.isGoalkeeper()).isTrue()
    }

    @Test
    fun `outfield player is not detected as goalkeeper`() {
        val player = PlayerEntry(playerName = "Striker", position = "25", goals = "2")
        assertThat(player.isGoalkeeper()).isFalse()
    }

    @Test
    fun `BOT goalkeeper does not appear in player awards`() {
        val match = createMatchWithGoalkeeperAndOutfield(
            gkName = null,
            gkPosition = "0",
            gkSaves = "5",
            gkRating = "8.0",
            outfieldPlayers = listOf(
                player("Player1", rating = "7.0"),
                player("Player2", rating = "6.5"),
            )
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField).isNotNull

        val destaques = embed.fields.firstOrNull { it.name == " DESTAQUES" }
        if (destaques != null) assertThat(destaques.value).doesNotContain("Goleiro BOT")

        val craque = embed.fields.firstOrNull { it.name == "⭐ CRAQUE DA PARTIDA" }
        if (craque != null) assertThat(craque.value).doesNotContain("Goleiro BOT")
    }

    @Test
    fun `goalkeeper saves are attached to the correct player`() {
        val match = MatchResponse(
            matchId = "test-123",
            timestamp = 1721267100L,
            clubs = mapOf(
                ourClubId to ClubMatchEntry(details = ClubDetails(name = "Our Club"), score = "2", result = "1"),
                oppClubId to ClubMatchEntry(details = ClubDetails(name = "Opp Club"), score = "1", result = "0"),
            ),
            players = mapOf(
                ourClubId to mapOf(
                    "gk_id" to PlayerEntry(
                        playerName = "Nosso Goleiro",
                        position = "0",
                        saves = "8",
                        goalsConceded = "1",
                        secondsPlayed = "5400",
                    ),
                    "player_id" to PlayerEntry(
                        playerName = "Nosso Atacante",
                        position = "25",
                        goals = "2",
                        saves = "0",
                        secondsPlayed = "5400",
                    ),
                ),
                oppClubId to emptyMap(),
            ),
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField).isNotNull
        assertThat(gkField!!.value).contains("Nosso Goleiro")
        assertThat(gkField.value).contains("8 defesas")
        assertThat(gkField.value).doesNotContain("Nosso Atacante")
    }

    @Test
    fun `singular form used for 1 save`() {
        val match = createMatchWithGoalkeeper(
            gkName = "GK",
            gkPosition = "0",
            gkSaves = "1",
            gkGoalsConceded = "0",
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField!!.value).contains("1 defesa")
        assertThat(gkField.value).doesNotContain("1 defesas")
    }

    // ── Archetype rendering ───────────────────────────────────────────────────

    @Nested
    inner class ArchetypeRendering {

        @Test
        fun `goalkeeper section contains the archetype title`() {
            // 4 saves, 0 goals, rating 8.0 → WALL
            val embed = buildEmbedForGk(
                saves = "4", goalsConceded = "0", rating = "8.0"
            ).embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" Paredão")
        }

        @Test
        fun `UNDER_SIEGE title shown when goalkeeper is bombarded`() {
            // 10 saves, 2 goals conceded, rating 5.3 → UNDER_SIEGE
            val embed = buildEmbedForGk(
                saves = "10", goalsConceded = "2", rating = "5.3"
            ).embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" Bombardeado")
        }

        @Test
        fun `POOR title shown when performance is poor`() {
            // 2 saves, 3 goals, rating 5.0 → POOR
            val embed = buildEmbedForGk(
                saves = "2", goalsConceded = "3", rating = "5.0"
            ).embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" Mão de Alface")
        }

        @Test
        fun `QUIET title shown when goalkeeper had almost no involvement`() {
            // 0 saves, 0 goals → QUIET
            val embed = buildEmbedForGk(
                saves = "0", goalsConceded = "0", rating = "7.0"
            ).embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" Discreto")
        }

        @Test
        fun `SOLID title shown for decent performance`() {
            // 3 saves, 1 goal, rating 7.0 → SOLID
            val embed = buildEmbedForGk(
                saves = "3", goalsConceded = "1", rating = "7.0"
            ).embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" Seguro")
        }

        @Test
        fun `goalkeeper section always contains a phrase`() {
            val embed = buildEmbedForGk(saves = "3", goalsConceded = "1", rating = "7.0").embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" \"")
        }

        private fun buildEmbedForGk(
            saves: String,
            goalsConceded: String,
            rating: String,
            goodDirectionSaves: String = "0",
        ): DiscordPayload {
            val match = MatchResponse(
                matchId = "arch-test",
                timestamp = 1721267100L,
                clubs = mapOf(
                    ourClubId to ClubMatchEntry(details = ClubDetails(name = "Our Club"), score = "2", result = "1"),
                    oppClubId to ClubMatchEntry(details = ClubDetails(name = "Opp"), score = "1", result = "0"),
                ),
                players = mapOf(
                    ourClubId to mapOf(
                        "gk" to PlayerEntry(
                            playerName         = "Goleiro",
                            position           = "0",
                            saves              = saves,
                            goalsConceded      = goalsConceded,
                            rating             = rating,
                            goodDirectionSaves = goodDirectionSaves,
                            secondsPlayed      = "5400",
                        ),
                        "p1" to player("Linha1"),
                    ),
                    oppClubId to emptyMap(),
                ),
            )
            return DiscordEmbedBuilder.build(match, ourClubId, zone)
        }
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private fun createMatchWithGoalkeeper(
        gkName: String?,
        gkPosition: String,
        gkSaves: String,
        gkGoalsConceded: String,
    ): MatchResponse = MatchResponse(
        matchId = "test-123",
        timestamp = 1721267100L,
        clubs = mapOf(
            ourClubId to ClubMatchEntry(details = ClubDetails(name = "Our Club"), score = "2", result = "1"),
            oppClubId to ClubMatchEntry(details = ClubDetails(name = "Opp Club"), score = "1", result = "0"),
        ),
        players = mapOf(
            ourClubId to mapOf(
                "gk_id" to PlayerEntry(
                    playerName    = gkName,
                    position      = gkPosition,
                    saves         = gkSaves,
                    goalsConceded = gkGoalsConceded,
                    secondsPlayed = "5400",
                ),
                "player1" to player("Player1", rating = "7.0"),
            ),
            oppClubId to emptyMap(),
        ),
    )

    private fun createMatchWithGoalkeeperAndOutfield(
        gkName: String?,
        gkPosition: String,
        gkSaves: String,
        gkRating: String,
        outfieldPlayers: List<PlayerEntry>,
    ): MatchResponse {
        val playersMap = mutableMapOf<String, PlayerEntry>()
        playersMap["gk_id"] = PlayerEntry(
            playerName    = gkName,
            position      = gkPosition,
            saves         = gkSaves,
            rating        = gkRating,
            secondsPlayed = "5400",
        )
        outfieldPlayers.forEachIndexed { i, p -> playersMap["player_$i"] = p }

        return MatchResponse(
            matchId = "test-123",
            timestamp = 1721267100L,
            clubs = mapOf(
                ourClubId to ClubMatchEntry(details = ClubDetails(name = "Our Club"), score = "2", result = "1"),
                oppClubId to ClubMatchEntry(details = ClubDetails(name = "Opp Club"), score = "1", result = "0"),
            ),
            players = mapOf(ourClubId to playersMap, oppClubId to emptyMap()),
        )
    }

    private fun player(
        name: String,
        rating: String      = "7.0",
        goals: String       = "0",
        assists: String     = "0",
        shots: String       = "0",
        passAttempts: String  = "20",
        passesMade: String    = "15",
        tackleAttempts: String = "5",
        tacklesMade: String    = "3",
        secondsPlayed: String  = "5400",
    ) = PlayerEntry(
        playerName     = name,
        position       = "14",
        goals          = goals,
        assists        = assists,
        rating         = rating,
        shots          = shots,
        passAttempts   = passAttempts,
        passesMade     = passesMade,
        tackleAttempts = tackleAttempts,
        tacklesMade    = tacklesMade,
        secondsPlayed  = secondsPlayed,
    )
}

package com.eafc26.discordstats.discord

import com.eafc26.discordstats.ea.model.ClubDetails
import com.eafc26.discordstats.ea.model.ClubMatchEntry
import com.eafc26.discordstats.ea.model.MatchResponse
import com.eafc26.discordstats.ea.model.PlayerEntry
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test
import java.time.ZoneId

/**
 * Tests for goalkeeper display in Discord embed.
 *
 * Key requirements:
 * - BOT goalkeeper with saves should be displayed
 * - Human goalkeeper with saves should be displayed
 * - Blank BOT name falls back to "Goleiro BOT"
 * - Goalkeeper saves remain attached to the correct player
 * - BOT goalkeeper never appears in player awards (Craque, Bagre, etc.)
 * - The goalkeeper section shows the archetype title (e.g. " Paredão")
 */
class GoalkeeperDisplayTest {

    private val ourClubId = "1104972"
    private val oppClubId = "99999"
    private val zone = ZoneId.of("America/Sao_Paulo")

    @Test
    fun `BOT goalkeeper with saves is displayed`() {
        val match = createMatchWithGoalkeeper(
            gkName = null,
            gkPosition = "0",
            gkSaves = "5",
            gkGoalsConceded = "2",
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField).isNotNull
        assertThat(gkField!!.value).contains("Goleiro BOT")
        assertThat(gkField.value).contains("5 defesas")
        assertThat(gkField.value).contains("2 gols sofridos")
    }

    @Test
    fun `human goalkeeper with saves is displayed`() {
        val match = createMatchWithGoalkeeper(
            gkName = "João Goleiro",
            gkPosition = "0",
            gkSaves = "7",
            gkGoalsConceded = "1",
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField).isNotNull
        assertThat(gkField!!.value).contains("João Goleiro")
        assertThat(gkField.value).contains("7 defesas")
        assertThat(gkField.value).contains("1 gol sofrido")  // singular
    }

    @Test
    fun `blank BOT name falls back to Goleiro BOT`() {
        val match = createMatchWithGoalkeeper(
            gkName = "   ",
            gkPosition = "0",
            gkSaves = "3",
            gkGoalsConceded = "0",
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField).isNotNull
        assertThat(gkField!!.value).contains("Goleiro BOT")
    }

    @Test
    fun `goalkeeper with position code 0 is detected`() {
        val gk = PlayerEntry(playerName = "TestGK", position = "0", saves = "5")
        assertThat(gk.isGoalkeeper()).isTrue()
    }

    @Test
    fun `goalkeeper with string goalkeeper is detected for backwards compatibility`() {
        val gk = PlayerEntry(playerName = "TestGK", position = "goalkeeper", saves = "5")
        assertThat(gk.isGoalkeeper()).isTrue()
    }

    @Test
    fun `outfield player is not detected as goalkeeper`() {
        val player = PlayerEntry(playerName = "Striker", position = "25", goals = "2")
        assertThat(player.isGoalkeeper()).isFalse()
    }

    @Test
    fun `BOT goalkeeper does not appear in player awards`() {
        val match = createMatchWithGoalkeeperAndOutfield(
            gkName = null,
            gkPosition = "0",
            gkSaves = "5",
            gkRating = "8.0",
            outfieldPlayers = listOf(
                player("Player1", rating = "7.0"),
                player("Player2", rating = "6.5"),
            )
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField).isNotNull

        val destaques = embed.fields.firstOrNull { it.name == " DESTAQUES" }
        if (destaques != null) assertThat(destaques.value).doesNotContain("Goleiro BOT")

        val craque = embed.fields.firstOrNull { it.name == "⭐ CRAQUE DA PARTIDA" }
        if (craque != null) assertThat(craque.value).doesNotContain("Goleiro BOT")
    }

    @Test
    fun `goalkeeper saves are attached to the correct player`() {
        val match = MatchResponse(
            matchId = "test-123",
            timestamp = 1721267100L,
            clubs = mapOf(
                ourClubId to ClubMatchEntry(details = ClubDetails(name = "Our Club"), score = "2", result = "1"),
                oppClubId to ClubMatchEntry(details = ClubDetails(name = "Opp Club"), score = "1", result = "0"),
            ),
            players = mapOf(
                ourClubId to mapOf(
                    "gk_id" to PlayerEntry(
                        playerName = "Nosso Goleiro",
                        position = "0",
                        saves = "8",
                        goalsConceded = "1",
                        secondsPlayed = "5400",
                    ),
                    "player_id" to PlayerEntry(
                        playerName = "Nosso Atacante",
                        position = "25",
                        goals = "2",
                        saves = "0",
                        secondsPlayed = "5400",
                    ),
                ),
                oppClubId to emptyMap(),
            ),
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField).isNotNull
        assertThat(gkField!!.value).contains("Nosso Goleiro")
        assertThat(gkField.value).contains("8 defesas")
        assertThat(gkField.value).doesNotContain("Nosso Atacante")
    }

    @Test
    fun `singular form used for 1 save`() {
        val match = createMatchWithGoalkeeper(
            gkName = "GK",
            gkPosition = "0",
            gkSaves = "1",
            gkGoalsConceded = "0",
        )

        val payload = DiscordEmbedBuilder.build(match, ourClubId, zone)
        val embed = payload.embeds[0]

        val gkField = embed.fields.firstOrNull { it.name == " GOLEIRO" }
        assertThat(gkField!!.value).contains("1 defesa")
        assertThat(gkField.value).doesNotContain("1 defesas")
    }

    // ── Archetype rendering ───────────────────────────────────────────────────

    @Nested
    inner class ArchetypeRendering {

        @Test
        fun `goalkeeper section contains the archetype title`() {
            // 4 saves, 0 goals, rating 8.0 → WALL
            val embed = buildEmbedForGk(
                saves = "4", goalsConceded = "0", rating = "8.0"
            ).embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" Paredão")
        }

        @Test
        fun `UNDER_SIEGE title shown when goalkeeper is bombarded with acceptable rating`() {
            // 10 saves, 2 goals conceded, rating 6.2 → UNDER_SIEGE (rating ≥ 6.0)
            val embed = buildEmbedForGk(
                saves = "10", goalsConceded = "2", rating = "6.2"
            ).embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" Bombardeado")
        }

        @Test
        fun `POOR title shown when goalkeeper has many saves but very low rating`() {
            // 10 saves, 2 goals conceded, rating 5.3 → POOR (low rating wins over save count)
            val embed = buildEmbedForGk(
                saves = "10", goalsConceded = "2", rating = "5.3"
            ).embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" Mão de Alface")
        }

        @Test
        fun `POOR title shown when performance is poor`() {
            // 2 saves, 3 goals, rating 5.0 → POOR
            val embed = buildEmbedForGk(
                saves = "2", goalsConceded = "3", rating = "5.0"
            ).embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" Mão de Alface")
        }

        @Test
        fun `QUIET title shown when goalkeeper had almost no involvement`() {
            // 0 saves, 0 goals → QUIET
            val embed = buildEmbedForGk(
                saves = "0", goalsConceded = "0", rating = "7.0"
            ).embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" Discreto")
        }

        @Test
        fun `SOLID title shown for decent performance`() {
            // 3 saves, 1 goal, rating 7.0 → SOLID
            val embed = buildEmbedForGk(
                saves = "3", goalsConceded = "1", rating = "7.0"
            ).embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" Seguro")
        }

        @Test
        fun `goalkeeper section always contains a phrase`() {
            val embed = buildEmbedForGk(saves = "3", goalsConceded = "1", rating = "7.0").embeds[0]
            val gkField = embed.fields.first { it.name == " GOLEIRO" }
            assertThat(gkField.value).contains(" \"")
        }

        private fun buildEmbedForGk(
            saves: String,
            goalsConceded: String,
            rating: String,
            goodDirectionSaves: String = "0",
        ): DiscordPayload {
            val match = MatchResponse(
                matchId = "arch-test",
                timestamp = 1721267100L,
                clubs = mapOf(
                    ourClubId to ClubMatchEntry(details = ClubDetails(name = "Our Club"), score = "2", result = "1"),
                    oppClubId to ClubMatchEntry(details = ClubDetails(name = "Opp"), score = "1", result = "0"),
                ),
                players = mapOf(
                    ourClubId to mapOf(
                        "gk" to PlayerEntry(
                            playerName         = "Goleiro",
                            position           = "0",
                            saves              = saves,
                            goalsConceded      = goalsConceded,
                            rating             = rating,
                            goodDirectionSaves = goodDirectionSaves,
                            secondsPlayed      = "5400",
                        ),
                        "p1" to player("Linha1"),
                    ),
                    oppClubId to emptyMap(),
                ),
            )
            return DiscordEmbedBuilder.build(match, ourClubId, zone)
        }
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private fun createMatchWithGoalkeeper(
        gkName: String?,
        gkPosition: String,
        gkSaves: String,
        gkGoalsConceded: String,
    ): MatchResponse = MatchResponse(
        matchId = "test-123",
        timestamp = 1721267100L,
        clubs = mapOf(
            ourClubId to ClubMatchEntry(details = ClubDetails(name = "Our Club"), score = "2", result = "1"),
            oppClubId to ClubMatchEntry(details = ClubDetails(name = "Opp Club"), score = "1", result = "0"),
        ),
        players = mapOf(
            ourClubId to mapOf(
                "gk_id" to PlayerEntry(
                    playerName    = gkName,
                    position      = gkPosition,
                    saves         = gkSaves,
                    goalsConceded = gkGoalsConceded,
                    secondsPlayed = "5400",
                ),
                "player1" to player("Player1", rating = "7.0"),
            ),
            oppClubId to emptyMap(),
        ),
    )

    private fun createMatchWithGoalkeeperAndOutfield(
        gkName: String?,
        gkPosition: String,
        gkSaves: String,
        gkRating: String,
        outfieldPlayers: List<PlayerEntry>,
    ): MatchResponse {
        val playersMap = mutableMapOf<String, PlayerEntry>()
        playersMap["gk_id"] = PlayerEntry(
            playerName    = gkName,
            position      = gkPosition,
            saves         = gkSaves,
            rating        = gkRating,
            secondsPlayed = "5400",
        )
        outfieldPlayers.forEachIndexed { i, p -> playersMap["player_$i"] = p }

        return MatchResponse(
            matchId = "test-123",
            timestamp = 1721267100L,
            clubs = mapOf(
                ourClubId to ClubMatchEntry(details = ClubDetails(name = "Our Club"), score = "2", result = "1"),
                oppClubId to ClubMatchEntry(details = ClubDetails(name = "Opp Club"), score = "1", result = "0"),
            ),
            players = mapOf(ourClubId to playersMap, oppClubId to emptyMap()),
        )
    }

    private fun player(
        name: String,
        rating: String      = "7.0",
        goals: String       = "0",
        assists: String     = "0",
        shots: String       = "0",
        passAttempts: String  = "20",
        passesMade: String    = "15",
        tackleAttempts: String = "5",
        tacklesMade: String    = "3",
        secondsPlayed: String  = "5400",
    ) = PlayerEntry(
        playerName     = name,
        position       = "14",
        goals          = goals,
        assists        = assists,
        rating         = rating,
        shots          = shots,
        passAttempts   = passAttempts,
        passesMade     = passesMade,
        tackleAttempts = tackleAttempts,
        tacklesMade    = tacklesMade,
        secondsPlayed  = secondsPlayed,
    )
}

package com.eafc26.discordstats.discord

import com.eafc26.discordstats.ea.model.PlayerEntry
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

/**
 * Tests for [GoalkeeperEvaluator].
 *
 * Classification priority (first match wins):
 *   1. QUIET          — saves ≤ 1 and goalsConceded ≤ 1
 *   2. WALL           — rating ≥ 7.5 and (cleanSheet or impactSaves ≥ 3)
 *   3. UNDER_SIEGE    — saves ≥ 6
 *   4. POOR           — rating < 6.0
 *   5. SOLID          — everything else
 */
class GoalkeeperEvaluatorTest {

    // ── helpers ────────────────────────────────────────────────────────────────

    private fun gk(
        saves: Int            = 0,
        goalsConceded: Int    = 0,
        rating: Double        = 7.0,
        goodDirectionSaves: Int = 0,
        reflexSaves: Int      = 0,
        parrySaves: Int       = 0,
    ) = PlayerEntry(
        playerName          = "GK",
        position            = "0",
        saves               = saves.toString(),
        goalsConceded       = goalsConceded.toString(),
        rating              = rating.toString(),
        goodDirectionSaves  = goodDirectionSaves.toString(),
        reflexSaves         = reflexSaves.toString(),
        parrySaves          = parrySaves.toString(),
        secondsPlayed       = "5400",
    )

    private fun classify(
        saves: Int            = 0,
        goalsConceded: Int    = 0,
        rating: Double        = 7.0,
        goodDirectionSaves: Int = 0,
        reflexSaves: Int      = 0,
        parrySaves: Int       = 0,
    ) = GoalkeeperEvaluator.classify(
        saves         = saves,
        goalsConceded = goalsConceded,
        rating        = rating,
        impactSaves   = goodDirectionSaves + reflexSaves + parrySaves,
        cleanSheet    = goalsConceded == 0,
    )

    // ── QUIET ──────────────────────────────────────────────────────────────────

    @Nested
    inner class Quiet {

        @Test
        fun `zero saves zero goals is QUIET`() {
            assertThat(classify(saves = 0, goalsConceded = 0, rating = 7.0))
                .isEqualTo(GoalkeeperArchetype.QUIET)
        }

        @Test
        fun `one save zero goals is QUIET`() {
            assertThat(classify(saves = 1, goalsConceded = 0, rating = 7.5))
                .isEqualTo(GoalkeeperArchetype.QUIET)
        }

        @Test
        fun `zero saves one goal is QUIET`() {
            assertThat(classify(saves = 0, goalsConceded = 1, rating = 6.0))
                .isEqualTo(GoalkeeperArchetype.QUIET)
        }

        @Test
        fun `one save one goal is QUIET`() {
            assertThat(classify(saves = 1, goalsConceded = 1, rating = 5.5))
                .isEqualTo(GoalkeeperArchetype.QUIET)
        }

        @Test
        fun `two saves takes it out of QUIET`() {
            // 2 saves, 0 goals, good rating → WALL (not QUIET)
            assertThat(classify(saves = 2, goalsConceded = 0, rating = 8.0))
                .isNotEqualTo(GoalkeeperArchetype.QUIET)
        }
    }

    // ── WALL ───────────────────────────────────────────────────────────────────

    @Nested
    inner class Wall {

        @Test
        fun `high rating with clean sheet is WALL`() {
            assertThat(classify(saves = 4, goalsConceded = 0, rating = 7.5))
                .isEqualTo(GoalkeeperArchetype.WALL)
        }

        @Test
        fun `high rating with impact saves is WALL even with goals conceded`() {
            assertThat(classify(saves = 5, goalsConceded = 2, rating = 8.0, goodDirectionSaves = 3))
                .isEqualTo(GoalkeeperArchetype.WALL)
        }

        @Test
        fun `exactly at WALL rating threshold with clean sheet is WALL`() {
            assertThat(classify(saves = 3, goalsConceded = 0, rating = 7.5))
                .isEqualTo(GoalkeeperArchetype.WALL)
        }

        @Test
        fun `rating just below WALL threshold is not WALL`() {
            assertThat(classify(saves = 3, goalsConceded = 0, rating = 7.49))
                .isNotEqualTo(GoalkeeperArchetype.WALL)
        }

        @Test
        fun `high rating with goals conceded and fewer than 3 impact saves is not WALL`() {
            assertThat(classify(saves = 4, goalsConceded = 2, rating = 8.0, goodDirectionSaves = 2))
                .isNotEqualTo(GoalkeeperArchetype.WALL)
        }
    }

    // ── UNDER_SIEGE ────────────────────────────────────────────────────────────

    @Nested
    inner class UnderSiege {

        @Test
        fun `six saves triggers UNDER_SIEGE`() {
            assertThat(classify(saves = 6, goalsConceded = 2, rating = 5.3))
                .isEqualTo(GoalkeeperArchetype.UNDER_SIEGE)
        }

        @Test
        fun `ten saves with poor rating is UNDER_SIEGE not POOR`() {
            // Production example: saves=10, goalsConceded=2, rating=5.3
            assertThat(classify(saves = 10, goalsConceded = 2, rating = 5.3, goodDirectionSaves = 3))
                .isEqualTo(GoalkeeperArchetype.UNDER_SIEGE)
        }

        @Test
        fun `exactly MIN_SAVES_UNDER_SIEGE is UNDER_SIEGE`() {
            assertThat(classify(saves = GoalkeeperEvaluator.MIN_SAVES_UNDER_SIEGE, goalsConceded = 1, rating = 6.5))
                .isEqualTo(GoalkeeperArchetype.UNDER_SIEGE)
        }

        @Test
        fun `five saves does not trigger UNDER_SIEGE`() {
            assertThat(classify(saves = 5, goalsConceded = 1, rating = 6.5))
                .isNotEqualTo(GoalkeeperArchetype.UNDER_SIEGE)
        }

        @Test
        fun `high saves with high rating and clean sheet is WALL not UNDER_SIEGE`() {
            // WALL has higher priority than UNDER_SIEGE
            assertThat(classify(saves = 8, goalsConceded = 0, rating = 9.0))
                .isEqualTo(GoalkeeperArchetype.WALL)
        }
    }

    // ── POOR ───────────────────────────────────────────────────────────────────

    @Nested
    inner class Poor {

        @Test
        fun `low rating with goals conceded is POOR`() {
            assertThat(classify(saves = 2, goalsConceded = 3, rating = 4.5))
                .isEqualTo(GoalkeeperArchetype.POOR)
        }

        @Test
        fun `rating exactly at POOR threshold is POOR`() {
            assertThat(classify(saves = 2, goalsConceded = 2, rating = 5.9))
                .isEqualTo(GoalkeeperArchetype.POOR)
        }

        @Test
        fun `rating at 6_0 is not POOR`() {
            assertThat(classify(saves = 2, goalsConceded = 2, rating = 6.0))
                .isNotEqualTo(GoalkeeperArchetype.POOR)
        }

        @Test
        fun `poor rating but six or more saves is UNDER_SIEGE not POOR`() {
            assertThat(classify(saves = 6, goalsConceded = 2, rating = 4.5))
                .isEqualTo(GoalkeeperArchetype.UNDER_SIEGE)
        }
    }

    // ── SOLID ──────────────────────────────────────────────────────────────────

    @Nested
    inner class Solid {

        @Test
        fun `average saves and moderate rating is SOLID`() {
            assertThat(classify(saves = 3, goalsConceded = 1, rating = 7.0))
                .isEqualTo(GoalkeeperArchetype.SOLID)
        }

        @Test
        fun `decent rating without clean sheet and not bombarded is SOLID`() {
            assertThat(classify(saves = 4, goalsConceded = 2, rating = 6.5))
                .isEqualTo(GoalkeeperArchetype.SOLID)
        }

        @Test
        fun `moderate rating with few saves and few goals is SOLID`() {
            assertThat(classify(saves = 2, goalsConceded = 1, rating = 6.5))
                .isEqualTo(GoalkeeperArchetype.SOLID)
        }
    }

    // ── Full evaluate() path ──────────────────────────────────────────────────

    @Nested
    inner class Evaluate {

        @Test
        fun `returns GoalkeeperPerformance with correct archetype and title`() {
            val result = GoalkeeperEvaluator.evaluate(
                gk(saves = 5, goalsConceded = 0, rating = 8.0),
                matchId = "match-001",
                phraseBank = null,
            )
            assertThat(result.archetype).isEqualTo(GoalkeeperArchetype.WALL)
            assertThat(result.title).isEqualTo(" Paredão")
            assertThat(result.message).isNotBlank()
        }

        @Test
        fun `message is not blank for every archetype`() {
            val cases = listOf(
                gk(saves = 0, goalsConceded = 0, rating = 7.0),                          // QUIET
                gk(saves = 4, goalsConceded = 0, rating = 8.0),                          // WALL
                gk(saves = 8, goalsConceded = 2, rating = 5.5),                          // UNDER_SIEGE
                gk(saves = 2, goalsConceded = 3, rating = 5.0),                          // POOR
                gk(saves = 3, goalsConceded = 1, rating = 7.0),                          // SOLID
            )
            cases.forEach { goalkeeper ->
                val result = GoalkeeperEvaluator.evaluate(goalkeeper, "m1", null)
                assertThat(result.message).isNotBlank()
            }
        }

        @Test
        fun `deterministic phrase selection produces same result for same matchId and name`() {
            val goalkeeper = gk(saves = 3, goalsConceded = 1, rating = 7.0)
            val r1 = GoalkeeperEvaluator.evaluate(goalkeeper, "match-abc", null)
            val r2 = GoalkeeperEvaluator.evaluate(goalkeeper, "match-abc", null)
            assertThat(r1.message).isEqualTo(r2.message)
        }

        @Test
        fun `archetype title matches enum title`() {
            GoalkeeperArchetype.entries.forEach { arch ->
                // build a GK that maps to this archetype and verify title consistency
                val result = GoalkeeperEvaluator.evaluate(
                    gkForArchetype(arch),
                    matchId = "t",
                    phraseBank = null,
                )
                assertThat(result.title).isEqualTo(arch.title)
            }
        }

        private fun gkForArchetype(arch: GoalkeeperArchetype) = when (arch) {
            GoalkeeperArchetype.QUIET       -> gk(saves = 0, goalsConceded = 0, rating = 7.0)
            GoalkeeperArchetype.WALL        -> gk(saves = 4, goalsConceded = 0, rating = 8.0)
            GoalkeeperArchetype.UNDER_SIEGE -> gk(saves = 8, goalsConceded = 2, rating = 5.5)
            GoalkeeperArchetype.POOR        -> gk(saves = 2, goalsConceded = 3, rating = 5.0)
            GoalkeeperArchetype.SOLID       -> gk(saves = 3, goalsConceded = 1, rating = 7.0)
        }
    }

    // ── Phrase category mapping ───────────────────────────────────────────────

    @Nested
    inner class PhraseCategoryMapping {

        @Test
        fun `every archetype maps to a distinct phrase category`() {
            val categories = GoalkeeperArchetype.entries
                .map { GoalkeeperEvaluator.phraseCategory(it) }
                .toSet()
            assertThat(categories).hasSize(GoalkeeperArchetype.entries.size)
        }
    }

    // ── Regression — production example ──────────────────────────────────────

    @Nested
    inner class ProductionRegression {

        /**
         * Real production GK with:
         * saves=10, goalsConceded=2, rating=5.3, goodDirectionSaves=3, others=0.
         *
         * With the OLD logic (raw save count), this was treated as a strong performance.
         * With the NEW logic it must be UNDER_SIEGE: many saves, goals conceded, poor rating.
         */
        @Test
        fun `bombardeado example is UNDER_SIEGE not POOR and not WALL`() {
            val result = GoalkeeperEvaluator.evaluate(
                gk(
                    saves              = 10,
                    goalsConceded      = 2,
                    rating             = 5.3,
                    goodDirectionSaves = 3,
                    reflexSaves        = 0,
                    parrySaves         = 0,
                ),
                matchId    = "prod-match-001",
                phraseBank = null,
            )
            assertThat(result.archetype).isEqualTo(GoalkeeperArchetype.UNDER_SIEGE)
            assertThat(result.title).isEqualTo(" Bombardeado")
            assertThat(result.message).isNotBlank()
        }

        /** Clean-sheet strong match → WALL. */
        @Test
        fun `clean sheet with high rating and impact saves is WALL`() {
            val result = GoalkeeperEvaluator.evaluate(
                gk(saves = 5, goalsConceded = 0, rating = 8.5, goodDirectionSaves = 3),
                matchId    = "prod-match-002",
                phraseBank = null,
            )
            assertThat(result.archetype).isEqualTo(GoalkeeperArchetype.WALL)
            assertThat(result.title).isEqualTo(" Paredão")
        }

        /** Very quiet match → QUIET. */
        @Test
        fun `goalkeeper with no saves and no goals conceded is QUIET`() {
            val result = GoalkeeperEvaluator.evaluate(
                gk(saves = 0, goalsConceded = 0, rating = 7.0),
                matchId    = "prod-match-003",
                phraseBank = null,
            )
            assertThat(result.archetype).isEqualTo(GoalkeeperArchetype.QUIET)
            assertThat(result.title).isEqualTo(" Discreto")
        }
    }
}

package com.eafc26.discordstats.discord

import com.eafc26.discordstats.ea.model.PlayerEntry
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

/**
 * Tests for [GoalkeeperEvaluator].
 *
 * Classification priority (first match wins):
 *   1. QUIET          — saves ≤ 1 and goalsConceded ≤ 1
 *   2. WALL           — rating ≥ 8.0 and (cleanSheet or impactSaves ≥ 3)
 *   3. POOR           — rating < 6.0  (EA verdict takes priority over save count)
 *   4. UNDER_SIEGE    — saves ≥ 6     (implicitly rating ≥ 6.0)
 *   5. SOLID          — everything else
 */
class GoalkeeperEvaluatorTest {

    // ── helpers ────────────────────────────────────────────────────────────────

    private fun gk(
        saves: Int              = 0,
        goalsConceded: Int      = 0,
        rating: Double          = 7.0,
        goodDirectionSaves: Int = 0,
        reflexSaves: Int        = 0,
        parrySaves: Int         = 0,
    ) = PlayerEntry(
        playerName         = "GK",
        position           = "0",
        saves              = saves.toString(),
        goalsConceded      = goalsConceded.toString(),
        rating             = rating.toString(),
        goodDirectionSaves = goodDirectionSaves.toString(),
        reflexSaves        = reflexSaves.toString(),
        parrySaves         = parrySaves.toString(),
        secondsPlayed      = "5400",
    )

    private fun classify(
        saves: Int              = 0,
        goalsConceded: Int      = 0,
        rating: Double          = 7.0,
        goodDirectionSaves: Int = 0,
        reflexSaves: Int        = 0,
        parrySaves: Int         = 0,
    ) = GoalkeeperEvaluator.classify(
        saves         = saves,
        goalsConceded = goalsConceded,
        rating        = rating,
        impactSaves   = goodDirectionSaves + reflexSaves + parrySaves,
        cleanSheet    = goalsConceded == 0,
    )

    // ── QUIET ──────────────────────────────────────────────────────────────────

    @Nested
    inner class Quiet {

        @Test
        fun `zero saves zero goals is QUIET`() {
            assertThat(classify(saves = 0, goalsConceded = 0, rating = 7.0))
                .isEqualTo(GoalkeeperArchetype.QUIET)
        }

        @Test
        fun `one save zero goals is QUIET`() {
            assertThat(classify(saves = 1, goalsConceded = 0, rating = 7.5))
                .isEqualTo(GoalkeeperArchetype.QUIET)
        }

        @Test
        fun `zero saves one goal is QUIET`() {
            assertThat(classify(saves = 0, goalsConceded = 1, rating = 6.0))
                .isEqualTo(GoalkeeperArchetype.QUIET)
        }

        @Test
        fun `one save one goal is QUIET`() {
            assertThat(classify(saves = 1, goalsConceded = 1, rating = 5.5))
                .isEqualTo(GoalkeeperArchetype.QUIET)
        }

        @Test
        fun `two saves takes it out of QUIET`() {
            // 2 saves, 0 goals, good rating → WALL (not QUIET)
            assertThat(classify(saves = 2, goalsConceded = 0, rating = 8.5))
                .isNotEqualTo(GoalkeeperArchetype.QUIET)
        }
    }

    // ── WALL ───────────────────────────────────────────────────────────────────

    @Nested
    inner class Wall {

        @Test
        fun `high rating with clean sheet is WALL`() {
            assertThat(classify(saves = 4, goalsConceded = 0, rating = 8.0))
                .isEqualTo(GoalkeeperArchetype.WALL)
        }

        @Test
        fun `high rating with impact saves is WALL even with goals conceded`() {
            assertThat(classify(saves = 5, goalsConceded = 2, rating = 8.0, goodDirectionSaves = 3))
                .isEqualTo(GoalkeeperArchetype.WALL)
        }

        @Test
        fun `exactly at WALL rating threshold with clean sheet is WALL`() {
            assertThat(classify(saves = 3, goalsConceded = 0, rating = 8.0))
                .isEqualTo(GoalkeeperArchetype.WALL)
        }

        @Test
        fun `rating just below WALL threshold is not WALL`() {
            assertThat(classify(saves = 3, goalsConceded = 0, rating = 7.99))
                .isNotEqualTo(GoalkeeperArchetype.WALL)
        }

        @Test
        fun `rating 7_5 is no longer WALL`() {
            // WALL_RATING_THRESHOLD raised from 7.5 to 8.0 — Paredão should feel special
            assertThat(classify(saves = 4, goalsConceded = 0, rating = 7.5))
                .isNotEqualTo(GoalkeeperArchetype.WALL)
        }

        @Test
        fun `high rating with goals conceded and fewer than 3 impact saves is not WALL`() {
            assertThat(classify(saves = 4, goalsConceded = 2, rating = 8.0, goodDirectionSaves = 2))
                .isNotEqualTo(GoalkeeperArchetype.WALL)
        }

        @Test
        fun `excellent rating with several impact saves is WALL`() {
            assertThat(classify(saves = 6, goalsConceded = 1, rating = 8.5, reflexSaves = 4))
                .isEqualTo(GoalkeeperArchetype.WALL)
        }
    }

    // ── POOR ───────────────────────────────────────────────────────────────────

    @Nested
    inner class Poor {

        @Test
        fun `low rating with goals conceded is POOR`() {
            assertThat(classify(saves = 2, goalsConceded = 3, rating = 4.5))
                .isEqualTo(GoalkeeperArchetype.POOR)
        }

        @Test
        fun `rating exactly at POOR threshold is POOR`() {
            assertThat(classify(saves = 2, goalsConceded = 2, rating = 5.9))
                .isEqualTo(GoalkeeperArchetype.POOR)
        }

        @Test
        fun `rating at 6_0 is not POOR`() {
            assertThat(classify(saves = 2, goalsConceded = 2, rating = 6.0))
                .isNotEqualTo(GoalkeeperArchetype.POOR)
        }

        @Test
        fun `poor rating with many saves is POOR not UNDER_SIEGE`() {
            // POOR is checked before UNDER_SIEGE — EA rating wins over save count
            assertThat(classify(saves = 6, goalsConceded = 2, rating = 4.5))
                .isEqualTo(GoalkeeperArchetype.POOR)
        }

        @Test
        fun `many saves and very low rating is POOR`() {
            // Regression: 8 saves, 5 goals conceded, rating 4.8 → POOR (not UNDER_SIEGE)
            assertThat(classify(saves = 8, goalsConceded = 5, rating = 4.8))
                .isEqualTo(GoalkeeperArchetype.POOR)
        }

        @Test
        fun `ten saves with poor rating is POOR not UNDER_SIEGE`() {
            // The EA rating is the verdict — a goalkeeper who made many routine saves
            // but still performed badly should not be described as UNDER_SIEGE
            assertThat(classify(saves = 10, goalsConceded = 4, rating = 5.0))
                .isEqualTo(GoalkeeperArchetype.POOR)
        }
    }

    // ── UNDER_SIEGE ────────────────────────────────────────────────────────────

    @Nested
    inner class UnderSiege {

        @Test
        fun `six saves with acceptable rating triggers UNDER_SIEGE`() {
            assertThat(classify(saves = 6, goalsConceded = 2, rating = 6.5))
                .isEqualTo(GoalkeeperArchetype.UNDER_SIEGE)
        }

        @Test
        fun `many saves with acceptable rating is UNDER_SIEGE`() {
            // saves=10, goalsConceded=2, rating=6.2 → acceptable rating → UNDER_SIEGE
            assertThat(classify(saves = 10, goalsConceded = 2, rating = 6.2))
                .isEqualTo(GoalkeeperArchetype.UNDER_SIEGE)
        }

        @Test
        fun `exactly MIN_SAVES_UNDER_SIEGE with acceptable rating is UNDER_SIEGE`() {
            assertThat(classify(saves = GoalkeeperEvaluator.MIN_SAVES_UNDER_SIEGE, goalsConceded = 1, rating = 6.5))
                .isEqualTo(GoalkeeperArchetype.UNDER_SIEGE)
        }

        @Test
        fun `five saves does not trigger UNDER_SIEGE`() {
            assertThat(classify(saves = 5, goalsConceded = 1, rating = 6.5))
                .isNotEqualTo(GoalkeeperArchetype.UNDER_SIEGE)
        }

        @Test
        fun `high saves with high rating and clean sheet is WALL not UNDER_SIEGE`() {
            // WALL has higher priority than UNDER_SIEGE
            assertThat(classify(saves = 8, goalsConceded = 0, rating = 9.0))
                .isEqualTo(GoalkeeperArchetype.WALL)
        }

        @Test
        fun `many saves with poor rating is POOR not UNDER_SIEGE`() {
            assertThat(classify(saves = 8, goalsConceded = 3, rating = 5.5))
                .isEqualTo(GoalkeeperArchetype.POOR)
        }
    }

    // ── SOLID ──────────────────────────────────────────────────────────────────

    @Nested
    inner class Solid {

        @Test
        fun `average saves and moderate rating is SOLID`() {
            assertThat(classify(saves = 3, goalsConceded = 1, rating = 7.0))
                .isEqualTo(GoalkeeperArchetype.SOLID)
        }

        @Test
        fun `decent rating without clean sheet and not bombarded is SOLID`() {
            assertThat(classify(saves = 4, goalsConceded = 2, rating = 6.5))
                .isEqualTo(GoalkeeperArchetype.SOLID)
        }

        @Test
        fun `moderate rating with few saves and few goals is SOLID`() {
            assertThat(classify(saves = 2, goalsConceded = 1, rating = 6.5))
                .isEqualTo(GoalkeeperArchetype.SOLID)
        }

        @Test
        fun `ordinary performance is SOLID`() {
            assertThat(classify(saves = 3, goalsConceded = 1, rating = 7.0))
                .isEqualTo(GoalkeeperArchetype.SOLID)
        }
    }

    // ── Full evaluate() path ──────────────────────────────────────────────────

    @Nested
    inner class Evaluate {

        @Test
        fun `returns GoalkeeperPerformance with correct archetype and title`() {
            val result = GoalkeeperEvaluator.evaluate(
                gk(saves = 5, goalsConceded = 0, rating = 8.0),
                matchId = "match-001",
                phraseBank = null,
            )
            assertThat(result.archetype).isEqualTo(GoalkeeperArchetype.WALL)
            assertThat(result.title).isEqualTo(GoalkeeperArchetype.WALL.title)
            assertThat(result.message).isNotBlank()
        }

        @Test
        fun `message is not blank for every archetype`() {
            val cases = listOf(
                gk(saves = 0, goalsConceded = 0, rating = 7.0),          // QUIET
                gk(saves = 4, goalsConceded = 0, rating = 8.0),          // WALL
                gk(saves = 8, goalsConceded = 2, rating = 6.5),          // UNDER_SIEGE
                gk(saves = 2, goalsConceded = 3, rating = 5.0),          // POOR
                gk(saves = 3, goalsConceded = 1, rating = 7.0),          // SOLID
            )
            cases.forEach { goalkeeper ->
                val result = GoalkeeperEvaluator.evaluate(goalkeeper, "m1", null)
                assertThat(result.message).isNotBlank()
            }
        }

        @Test
        fun `deterministic phrase selection produces same result for same matchId and name`() {
            val goalkeeper = gk(saves = 3, goalsConceded = 1, rating = 7.0)
            val r1 = GoalkeeperEvaluator.evaluate(goalkeeper, "match-abc", null)
            val r2 = GoalkeeperEvaluator.evaluate(goalkeeper, "match-abc", null)
            assertThat(r1.message).isEqualTo(r2.message)
        }

        @Test
        fun `archetype title matches enum title`() {
            GoalkeeperArchetype.entries.forEach { arch ->
                val result = GoalkeeperEvaluator.evaluate(
                    gkForArchetype(arch),
                    matchId = "t",
                    phraseBank = null,
                )
                assertThat(result.title).isEqualTo(arch.title)
            }
        }

        private fun gkForArchetype(arch: GoalkeeperArchetype) = when (arch) {
            GoalkeeperArchetype.QUIET       -> gk(saves = 0, goalsConceded = 0, rating = 7.0)
            GoalkeeperArchetype.WALL        -> gk(saves = 4, goalsConceded = 0, rating = 8.0)
            GoalkeeperArchetype.UNDER_SIEGE -> gk(saves = 8, goalsConceded = 2, rating = 6.5)
            GoalkeeperArchetype.POOR        -> gk(saves = 2, goalsConceded = 3, rating = 5.0)
            GoalkeeperArchetype.SOLID       -> gk(saves = 3, goalsConceded = 1, rating = 7.0)
        }
    }

    // ── Phrase category mapping ───────────────────────────────────────────────

    @Nested
    inner class PhraseCategoryMapping {

        @Test
        fun `every archetype maps to a distinct phrase category`() {
            val categories = GoalkeeperArchetype.entries
                .map { GoalkeeperEvaluator.phraseCategory(it) }
                .toSet()
            assertThat(categories).hasSize(GoalkeeperArchetype.entries.size)
        }
    }

    // ── Regression — production examples ──────────────────────────────────────

    @Nested
    inner class ProductionRegression {

        /**
         * Many saves but very low rating → POOR.
         * The EA rating is the primary verdict; a goalkeeper who let in many goals
         * despite making saves should not be described as "bombarded" ("Bombardeado").
         */
        @Test
        fun `many saves and very low rating is POOR not UNDER_SIEGE`() {
            val result = GoalkeeperEvaluator.evaluate(
                gk(
                    saves              = 10,
                    goalsConceded      = 2,
                    rating             = 5.3,
                    goodDirectionSaves = 3,
                ),
                matchId    = "prod-match-001",
                phraseBank = null,
            )
            assertThat(result.archetype).isEqualTo(GoalkeeperArchetype.POOR)
            assertThat(result.message).isNotBlank()
        }

        /**
         * Many saves with an acceptable rating → UNDER_SIEGE.
         * The goalkeeper was genuinely bombarded and generally did his job.
         */
        @Test
        fun `many saves and acceptable rating is UNDER_SIEGE`() {
            val result = GoalkeeperEvaluator.evaluate(
                gk(
                    saves         = 10,
                    goalsConceded = 2,
                    rating        = 6.2,
                ),
                matchId    = "prod-match-004",
                phraseBank = null,
            )
            assertThat(result.archetype).isEqualTo(GoalkeeperArchetype.UNDER_SIEGE)
            assertThat(result.title).isEqualTo(GoalkeeperArchetype.UNDER_SIEGE.title)
            assertThat(result.message).isNotBlank()
        }

        /** Excellent rating + clean sheet → WALL. */
        @Test
        fun `clean sheet with high rating is WALL`() {
            val result = GoalkeeperEvaluator.evaluate(
                gk(saves = 5, goalsConceded = 0, rating = 8.5),
                matchId    = "prod-match-002",
                phraseBank = null,
            )
            assertThat(result.archetype).isEqualTo(GoalkeeperArchetype.WALL)
            assertThat(result.title).isEqualTo(GoalkeeperArchetype.WALL.title)
        }

        /** Excellent rating + several impact saves → WALL. */
        @Test
        fun `high rating with several impact saves is WALL`() {
            val result = GoalkeeperEvaluator.evaluate(
                gk(saves = 5, goalsConceded = 0, rating = 8.5, goodDirectionSaves = 3),
                matchId    = "prod-match-005",
                phraseBank = null,
            )
            assertThat(result.archetype).isEqualTo(GoalkeeperArchetype.WALL)
        }

        /** Quiet match → QUIET. */
        @Test
        fun `goalkeeper with no saves and no goals conceded is QUIET`() {
            val result = GoalkeeperEvaluator.evaluate(
                gk(saves = 0, goalsConceded = 0, rating = 7.0),
                matchId    = "prod-match-003",
                phraseBank = null,
            )
            assertThat(result.archetype).isEqualTo(GoalkeeperArchetype.QUIET)
            assertThat(result.title).isEqualTo(GoalkeeperArchetype.QUIET.title)
        }

        /** Ordinary performance → SOLID. */
        @Test
        fun `ordinary match is SOLID`() {
            val result = GoalkeeperEvaluator.evaluate(
                gk(saves = 3, goalsConceded = 1, rating = 7.0),
                matchId    = "prod-match-006",
                phraseBank = null,
            )
            assertThat(result.archetype).isEqualTo(GoalkeeperArchetype.SOLID)
        }
    }
}
